import akka.http.scaladsl.model.{HttpRequest, HttpResponse}
object AkkaHttpExample extends App {
  import Http().singleRequest(HttpRequest(uri = "http://some.url"))
  implicit val mat = ActorSystem("http-example").asMaterializer()

  def getPostUrl(): Unit = {
    println(s"Use POST to pass URL to fetch.")
    println(s"Type 'quit' or Ctrl+c to exit.")

    var response: Option[HttpResponse] = None
    while (response.isEmpty) {
      response = try {
        Http().singleRequest(HttpRequest(uri = "http://some.url")).toSingle().run()
      } catch { case e => None; }
      if (!response.isEmpty) println(s"Response: ${response}") else ()
    }
  }

  def main(): Unit = {
    getPostUrl()

    println("Type 'quit' or Ctrl+c to exit.")
    Await.result(System.in.readLine())
    mat.terminate()
